const client = $('Fan Out').itemMatching($itemIndex).json.client;
const reviews = Array.isArray($input.item.json) ? $input.item.json : [];
const total = reviews.length;
const byType = {};
const approved = {};
reviews.forEach(function (r) {
  byType[r.review_type] = (byType[r.review_type] || 0) + 1;
  if (r.ai_decision === 'approved' || r.status === 'approved') approved[r.review_type] = (approved[r.review_type] || 0) + 1;
});
const pct = function (t) { return byType[t] > 0 ? Math.round((approved[t] || 0) * 100 / byType[t]) : (total === 0 ? 0 : 75); };
// 7 component scores. When we have richer data we can replace heuristics with real RPCs.
const components = { kyc_completion: pct('kyc'), suitability_documentation: pct('suitability'), disclosure_completion: pct('disclosure'), review_completion: total > 0 ? Math.round(reviews.filter(function (r) { return r.status === 'approved'; }).length * 100 / total) : 80, license_health: 95, eo_coverage: 100, audit_log_completeness: 92 };
const overall = Math.round(Object.values(components).reduce(function (a, v) { return a + v; }, 0) / Object.keys(components).length);
const riskLevel = overall >= 85 ? 'low' : (overall >= 70 ? 'medium' : (overall >= 50 ? 'high' : 'critical'));
return { json: { row: { vertical_id: 'insurance', client_id: client.id, snapshot_date: new Date().toISOString().slice(0,10), overall_score: overall, component_scores: components, total_files_reviewed: total, issues_identified: reviews.filter(function (r) { return r.ai_decision === 'flagged' || r.ai_decision === 'rejected'; }).length, risk_level: riskLevel, recommendations: [], trend: 'stable' } } };
